import{_ as p,o as e,c as a,j as r,a as t,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.6.4.近战专长","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/2.建卡相关/2.6.专长/2.6.4.近战专长.md","filePath":"1.基础规则/2.建卡相关/2.6.专长/2.6.4.近战专长.md"}'),n={name:"1.基础规则/2.建卡相关/2.6.专长/2.6.4.近战专长.md"};function d(s,b,_,l,h,i){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"_2-6-4-近战专长",tabindex:"-1"},[t("2.6.4.近战专长 "),r("a",{class:"header-anchor",href:"#_2-6-4-近战专长","aria-label":'Permalink to "2.6.4.近战专长"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),o('<h1 id="近战专长" tabindex="-1">近战专长 <a class="header-anchor" href="#近战专长" aria-label="Permalink to &quot;近战专长&quot;">​</a></h1><p>近战专长</p><p>非身份专长的价格为：1级1点、2级3点、3级6点、4级12点专长点。</p><p>无双剑士（1—2）<br> 1级：星芒蝶舞<br> 使用非重剑的剑类武器进行武技检定时额外获得等于专长等级的技艺加值。<br> 2级：穿水入烟<br> 使用非重剑的剑类武器进行获得敏捷上附加成功数两倍的破甲，并且使用剑进行全力攻击时获得的基础防御减值会减少1点。</p><p>豪烈刀客（1—2）<br> 1级：武圣拖刀<br> 使用刀类武器进行攻击时，一回合一次，自由动作消耗1点意志，在下一次攻击中，你所持的刀类武器伤害提升力量上附加成功数。<br> 2级：乾坤破阵<br> 使用刀类武器进行攻击时，额外获得力量一半的破甲。</p><p>居合道（1–2）<br> 即日本剑道中的一种杀人术，其核心在于速度与反应更胜敌方一筹的拔出剑刃，在敌方尚未反应过来之时斩下对方首级。<br> 需求：敏捷4、沉着2<br> 你必须仅持握一柄武器体积不超过人物体积-2的有鞘白刃武器来使用该专长。<br> 1级:你可以将本专长等级加入先攻。若你持握的武器未出鞘，则人物获得专长等级的洞察防御；若你持握的武器已经出鞘，则人物攻击上获得专长等级的洞察加值。<br> 2级：当你持握的武器尚未出鞘时，你可以一个花招动作调整自己的持握武器姿势。此时你躯体看起来会隐约的向前倾斜，拇指轻推刀镡，刃锋略微露出刀鞘。<br> 调整姿势后的本回合内，本专长提供的先攻加值翻倍，你此时对先攻低于你的对手进行的攻击获得D级【先制】效果，且攻击上获得3点速度加值。</p><p>大巧不工（1-2）<br> 1级：<br> 使用重剑进行格挡时，可额外将重剑武器伤害提供的破防等量加入格挡防御之中，但不能超过此专长等级。重剑武器伤害提供的破防类型将转换为威猛。<br> 2级：<br> 使用重剑进行攻击时，可以选择在本次攻击中失去等同于本专长等级点武器伤害，并在此次攻击中获得【余波】。</p><p>龙胆枪侠（1—2）<br> 1级：五虎断门<br> 使用枪类武器时，获得等于专长等级的格挡防御（无需格挡）。<br> 2级：大漠孤烟，长河落日<br> 使用枪类武器时，仅在攻击单个目标时获得5点破甲，仅在攻击多个目标时获得5点威猛。</p><p>愤怒信徒（1—2）<br> 1级：死斗搏击<br> 你的全身视为武器伤害为3L的天生武器。<br> 2级：战争暴徒<br> 你的天生武器获得等于力量上附加成功数的武器伤害，并且在肉搏攻击时获得敏捷属性上附加成功数的高速或力量属性上附加成功数的威猛。</p><hr><p>「Ghetto」风格肉搏专长组</p><p>突击圣徒（1）<br> 突然袭击，用下作的手段和阴狠的指尖武器，你信奉这样的教条，并时刻践行。<br> 突击圣徒要求你使用指虎时才能施展，且指虎必须套在手上。<br> 你可以加大出拳的速度和力度，用指虎将你的敌人打破相，现在，当你使用指虎进行肉搏检定时，若你在本次攻击中占有【先制】，则你还可以在攻击上附带1点高速和1点威猛。现在，你至多可以将等同于「Ghetto」风格肉搏专长组获得专长个数的指虎上的附加成功转化为3DP攻击检定上表现加值。</p><p>Tanqueray（2）<br> 前提：突击圣徒（1）<br> 又是一记重拳，狠狠的教训那些不知天高地厚的小毛孩，让他们尝尝铁拳的滋味。<br> 在你使用指虎进行对特殊部位的攻击时，你还可以至多抵消其中2点部位上的减值，如果你攻击的是头部，则再额外抵消1点。</p><p>刁钻重拳（2）<br> 前提：突击圣徒（1）<br> 一拳、两拳，拳头总是能打到他们防不住的地方，不仅如此，他们也挡不住。<br> 在购买此专长后，你的其中一只手视为在攻击时具有刁钻（即使它戴着指虎）。若被你攻击的目标具有格挡，则你视为可以破除对方的D1C2B3A4S5点（随自身的力量附加而提升）格挡，并再为你具有刁钻的那只手提供1点武器伤害。</p><p>指虎玩咖（2）<br> 前提：突击圣徒（1）<br> 你运用指虎已越来越熟练，就像是在使用你的拳头一样，几乎已无法再感觉到它作为附庸的存在。<br> 当你使用指虎进行攻击时，你可以放弃指虎上的数点武器附加成功，并将每1点附加成功转化为3DP攻击检定上的表现加值和1点威猛，最多能以此法转换3点，这个能力与「突击圣徒」共享转换上限。<br> 现在，你可以在双手上佩戴不同的指虎，它们的基础属性无法一同生效，但你使用其中一只指虎时，可以同时享受另一只指虎的特殊效果。</p><p>Bloody Mary（3）<br> 前提：Tanqueray（2）<br> 连续的重拳将你的对手打的涕泗横流，一同流出来的还有泊泊黑血，沾满了你的指骨和冰冷的指虎。<br> 你可以如同具有连射一样进行肉搏攻击，表现形式为连续快速的出拳。<br> 当你使用指虎进行肉搏攻击时，你视为具有毁灭一般进行攻击，在此时，你可以将突击圣徒的转换附加效果改为用3点攻击检定DP转换为附加，上限与规定上限相同。<br> 在此基础上，再获得1点基于指虎武器的附加成功。</p><p>恶意中伤（3）<br> 前提：刁钻重拳（2）<br> 打断他们的骨头，击碎他们的鼻梁，让他们尝尝血的滋味。<br> 现在，当你使用指虎进行一次攻击时，可以将你造成的额外冲击点数等量转化为肢体妨碍点数，标准豁免。<br> 若你攻击了对方的特殊部位，且你的攻击出目超过对方的体积，则每1点超出的伤害都还会附带1点剧痛点数，对方使用标准豁免进行对抗。</p><p>肆意涂鸦（3）<br> 前提：指虎玩咖（2）<br> 用他们的血来让你平静，这是街面的规矩，如果接受不了，就滚出这里，让街区变成你的个人秀场。<br> 当你使用指虎进行攻击时，基于「指虎玩咖」的效果，你可以将可转化的附加数提升至6点（这并不意味着你能超过上限）。<br> 若你在一次攻击中成功的破除了被攻击者的任意点格挡，则你可以将等同于破除格挡数量的每2点严重伤害转化为1点不可豁免的流血点数，最多转化4点。</p><hr><p>诡诈奸兵（1—2）<br> 1级：蝎刺<br> 使用体积在2及以下短兵类武器时，忽略敌人等于专长等级的基础防御。<br> 2级：龙吻<br> 使用体积在2及以下短兵类武器时，获得敏捷上附加成功数的高速，并且在攻击特定部位时忽略等量减值。</p><p>庞然重锤（1—2）<br> 1级：粉碎<br> 使用锤类武器时，获得等于专长等级两倍的威猛。<br> 2级：劫掠<br> 使用锤类武器时，每次攻击附带一次冲撞，以造成的伤害作为冲撞检定的DC，反射豁免。</p><p>飓风蛮斧（1—2）<br> 1级：狂风呼啸<br> 使用斧类武器时，在全力攻击的时候额外获得专长等级的加值。<br> 2级：开山裂地<br> 使用斧类武器时，攻击时额外获得力量上附加成功一半的附加成功。</p><p>高山阵地（1—2）<br> 1级：鱼鳞防线<br> 使用长柄类武器时，武器视为拥有专长等级的【格挡】<br> 2级：山崩<br> 使用长柄类武器时，武器攻击范围视为D级困难地形，并且攻击时忽略敌人你敏捷上附加成功数的基础防御。</p><p>破军重武（1—2）<br> 1级：浮云摩顶<br> 使用具有双手特性的近战武器时，可将攻击上不超过专长等级点附加成功以1：4的比例转化为攻击dp上的器械加值。<br> 2级：平观四众<br> 使用具有双手特性的近战武器时，可同时攻击触及范围内每一个目标。</p><p>阿修罗（1—2）<br> 1级：障蔽日月<br> 在使用多把专业等级相同的武器时，可以在攻击时将所持有的所有武器加入其中，武器伤害取最高，攻击范围取最低，武器除基础属性外的特殊效果同时加入这次攻击。并且在格挡的伤害，除了作为主要格挡的武器以外，每加入一把就获得1点格挡加值。<br> 2级：无间天魔<br> 在使用多把专业等级相同的武器时，在一次攻击中每有1把武器就获得1点附加成功。</p><p>野蛮热诚（1—2）<br> 1级：勇武有力<br> 使用具有沉重武器时，力量需求下降等于专长*2等级的数值。<br> 2级：势大力沉<br> 使用具有沉重武器时，力量需求每有1点就获得1点威猛，上限为力量属性的一半。（以不计算1级下降效果的情况下，最终力量需求作为计算条件，如果是单手持有双手特性的武器时，以翻倍后力量需求为计算条件）</p><p>跃动舞者（1—2）<br> 1级：先发制人<br> 使用具有轻灵特性的武器时，可获得专长等级两倍的先攻。<br> 2级：出其不意<br> 使用具有轻灵特性的武器时，获得敏捷上附加成功数的高速，并且在敏捷/感知较高属性低于你敏捷属性的目标时，你的攻击附带C级措手不及效果。</p><p>形意鞭劲（1—2）<br> 1级：游龙惊鸿<br> 使用软兵器类的武器时，获得等于专长等级的高速。<br> 2级：灵蛇缠舞<br> 使用软兵器类的武器时，可以对被擒抱住的敌人造成严重伤害，并且在进行擒抱检定的时候获得1点附加成功。</p><p>复仇者（1—3）<br> 1级<br> 使用镰刀进行攻击时，攻击视为拥有黑暗能量，但是不视为拥有能量武器特性，获得1点破魔。<br> 2级<br> 消耗一个自由动作，令下一次以镰刀进行攻击时，可以提升1点附加成功，如果成功造成伤害，则回复自身1点严重生命至完好（医疗点12）。<br> 3级<br> 使用本专长的2级用法时，附加成功再提升2点，造成伤害回复的生命提升1点（医疗点40，替换二级效果）。</p><p>拳王（1-2）<br> 1级：灵巧步伐<br> 经过长久的训练，你的脚步灵活异常，你在进行肉搏格挡时即使你对应的格挡技能上没有附加成功也可以全速移动，你在进行肉搏攻击可以攻击你触及范围内的两个不同的目标。<br> 2级：拳王绝学<br> 现你已经做好了成为一位拳王的准备，你的拳击技巧精湛，力道凶狠，消耗一个标准动作进行一次肉搏攻击，在这次攻击中你可以选择触发一种来自拳王的战斗技巧。<br> 蜂刺：来自拳王阿里的绝技，如蜜蜂般钉刺，你进行一次肉搏攻击，这次攻击并不会造成伤害，而是造成等同于你出数点剧痛点数<br> 蹬羚：字如其名，如一只羚羊般腾跃，攻击，拳王泰森的成名绝技。你可以将本次攻击结合至一次移动中进行，并在本轮中获得一次自由动作冲撞的机会。</p><p>顾应剑法（1—4）<br> 使用条件：左右手各持一把剑类近战武器<br> “刘先主之顾应法”虽然实际上是否和刘备有关尚有争议，但总有这么个剑法。<br> 1级：攻守兼备<br> 顾应法攻守兼备。攻击方面，若你进行的一次单体攻击的计算中包含且仅包含一把剑的武器伤害，那么你可以使用另一只手上的那把剑对攻击范围内的另一个目标同时进行同样的攻击，此时使用另一只手上的剑的武器伤害进行相关计算。防守方面，你可以忽略1点多次攻击减值。<br> 2级：左顾右应<br> 你使用其中一把剑进行招架时。根据你的武技以及这把剑的武器伤害<br> 武技5及以上，武器伤害3及以上，此次招架获得的伤害出目抵消加一<br> 武技8及以上，武器伤害6及以上，此次招架获得的伤害出目再抵消加一<br> 武技11及以上，武器伤害9及以上，此次招架获得的伤害出目抵消再加一<br> 3级：顾而应之<br> 若你在自身回合内声明保留了一个可用于攻击的标准动作与一个可用于防御的移动动作，则在你攻击范围内的敌人对你发动攻击时，你可以使用一个反射动作使用一把剑进行招架，同时使用另一把剑攻其不备。首先判定你的此次攻击(此次攻击必须是使用一把剑进行的单体攻击，也就是说这次攻击的计算公式中必须包含一把剑的武器伤害,这次攻击不能附加标准动作使用的招式)，你的此次攻击视为具有C级措手不及。之后若对方仍能发动此次攻击，你在计算这次攻击时正常获得招架的效果（此时“左顾右应”必须使用与攻击的剑不同一把剑进行相关计算）。<br> 本能力每轮只能使用一次。<br> 4级：剑法大成<br> 前提：武技等级11及以上<br> 现在，你使用“顾而应之”的效果只需要保留一个可用于防御的移动动作。若如此做，视为你同时转换了一个标准动作。</p><p>拳打脚踢（2）<br> 前提：武技2，具有拳/腿专业之一<br> 人物可以【拳】专业代替【腿】专业或用【腿】专业代替【拳】专业进行攻击检定，在购买时选择，不可更改。<br> 在攻击时，人物可以以拳腿展开攻击的铺垫。每轮一次，在攻击开始时以自由动作进行一次扫腿或下重拳迫使敌人倒地（肉搏绊摔检定，正常对抗），随后再以拳脚对到底的敌人进行追击。</p><p>饥渴大斧（1—4）<br> 1级：柴山斧法<br> 你的大斧才刚刚开始饥渴难耐，你现在充其量配砍砍山里头的柴火，但是砍柴火，也有讲究，要能力灌斧刃，深深嵌入。<br> 你现在以斧进行攻击时，可以减少自身4点dp，获得5点破甲。<br> 2级：上阵杀敌<br> 经过长久的练习，你终于配上阵持斧，现在，你的大斧终于可以对敌人的鲜血饥渴难耐了。<br> 战场上，露出破绽就等于丢掉性命，因此，你在以斧进行全力攻击时，收到的防御减值减少2点，并且你在以斧进行攻击时获得4点专长加值。<br> 3级：混世魔王<br> 说得很好听，但是意思其实是，虽然你用斧已有小成，但是也就和程咬金一样，会个唬人的三板斧罢了。<br> 你在一场战斗的前三轮中，第一轮，武器伤害提升3L，第二轮，在第一轮的基础上，在额外获得2点以斧攻击时的附加成功，第三轮，你可以消耗2点意志力令下一次攻击具有9点专长加值和1点附加成功，前两次并且继承前两轮的增益。做出这次攻击后，本场战斗中，这个专长失效。<br> 4级：力劈华山<br> 虽然力劈华山是一个已经被用烂了的技能名字，甚至听起来很掉价，但是并不妨碍那两位劈山救母的，都是三界中的狠角色，而你用斧的时候，也是这样。<br> 你在以斧进行的攻击获得【湮灭】特性，如果因其他资源导致你已经获得【湮灭】，改为令你具有【8加骰】，如果【8加骰】也已经具有，则改为令你获得4点以斧攻击时的附加成功。<br> 你以斧攻击时，每具有一点力量上的附加成功，这次攻击就具有3点【威猛】。</p><p>绳镖（1—2）<br> 前提：敏捷3，沉着2，武技2，使用绳镖<br> 1级：兵行诡道<br> 练的好退敌，练不好自危！<br> 使用绳镖进行攻击时，额外获得1点高速和1点破甲。这体现为你在使用绳镖时总能快速找到对方的防御较薄弱处进行打击。<br> 2级：喜鹊登枝<br> 抬腿，挂镖，甩腿，镖出如蛇，游走随意！<br> 当你使用绳镖进行攻击时，再额外获得5点高速，若本次攻击中，敌人的闪避防御在计算完你的高速后被扣除至零，则你可以在攻击范围内再指定一个敌人进行攻击。以此方式可至多额外指定两个目标。</p><p>魔杖（1-2）<br> 1级：疾风连打<br> 你的杖尖可以灵活而频繁的击打敌人的关节，不致死，但足以让对手缴械投降。<br> 现在，使用单手杖/刃杖/短棍攻击时还会额外使被攻击者承受2点多次攻击减值。<br> 2级：直击七寸<br> 精准的命中敌人的要害是必修课，不偏不倚的一击使敌人失去战斗能力。<br> 现在，使用单手杖/刃杖/短棍攻击头部时，还会将造成的部位攻击效果从【每2点伤害造成1点晕眩，以耐力-求生-强韧对抗】变为【如果伤害超过了对方的体积，则额外附带本次攻击的伤害出目扣除对方体积点晕眩，以标准豁免进行对抗】，并在此次攻击上获得1点附加成功。</p><p>于刀尖上舞蹈（2）<br> 前提：武技3，运动2<br> 2级：刃尖天鹅<br> 你现在可以将匕首在脚掌上镶嵌，学习该专长后，你的匕首武器将可改为占用你的鞋靴位进行握持，若如此做，你可以【腿】专业代替【匕首】专业进行检定。<br> 若你具有天生武器伤害，你可以在攻击后以一个自由动作用镶嵌匕首的腿进行一次硬踹将敌人击飞出去，（肉搏冲撞检定，正常对抗），将自己处于安全的范围内。</p><p>缴械（1-3）<br> 专长要求：力量3+，感知3+，敏捷2+，武技2+<br> 你必须以具有抓握，夹取或啃咬功能的武器来施展此专长。例如拳脚<br> ，利齿、长鞭和连枷。<br> 1级：精通缴械<br> 全神贯注，通过理解武器的握持方式和敌人的攻击模式，利用精准度和速度，你学会了如何让在近战中抓住敌人的武器。<br> 当你进行击落武器时，忽略等同于专长点的部位减值。<br> 2级：手腕落<br> 和谐地使用对方的力量，而不是与之对抗，通过技巧和身体力学，你能够在不使用过多力量的情况下，使对手摔倒并失去武器。<br> 当你进行击落武器前，你可以消耗自由动作进行一次绊摔，通过抓取对方持械手腕并下压的方式，使用名为手腕落（Ude-osae）的技巧，利用杠杆原理和身体的移动来伤害对手关节迫使其倒地。<br> 当你具有该专专长的三级后，因你的此技巧而倒地的对手，其持械手（双手武器则是其中一肢）受到3点肢体妨碍，强韧豁免。<br> 对因此倒地的目标进行的击落武器攻击，则对方会因为你压制着他的持械手，在击落武器的对抗中处于劣势，你将因此获得等同专长等级的增强加值。<br> 3级：武器舞者<br> 你的缴械技巧已经达到了一种艺术形式，能够在战斗中几乎无懈可击地夺取敌人的武器，然后立刻以缴械的武器发起反击。<br> 当你成功击落武器后，若你成功的夺取对方武器，你可以选择立即以迅捷动作，透支下一回合标准动作，以抢夺而来的武器进行一次攻击，并视为具有所缴械武器的1级相关专业，但依然需要满足武器的使用需求。</p><p>枪术师（1-3）<br> 前提：持用可造成穿刺伤害的长柄武器<br> 1级：鬼哭<br> 鬼哭队在长久的训练下研发出了一套迅捷的枪术，正与龙骑士们所使用的枪法相符。在以分类为【长枪】或其它造成物理-穿刺伤害的长柄武器进行战斗时视为以枪术进行战斗，具有等同于该专长等级的专长加值。<br> 2级：狼嚎<br> 狩猎与巡逻安保一直是长枪与生俱来的使命，毋庸置疑；从中磨砺而出的枪术以精湛闻名。以枪术进行战斗时，额外具有自身敏捷属性一半的高速。<br> 3级：狮吼<br> 雪原之上，骑士们将自己的枪术磨砺，直到自身也如一柄长枪般锋锐。以枪术进行战斗时，额外提升自身1/4力量属性点的武器伤害；全力攻击时额外获得1dp专长加值。<br> 枪术师们不断精进自身的战斗技艺，其中最为标志性的就是高高跃起进行下坠攻击的各类跳跃技艺，从中，枪术师们学会了如何偏转自身的坠落伤害，同时对敌人造成伤害，现在枪术师无视坠落伤害，若坠落时将会接触到某个敌人，运用空战技巧，枪术师们会在自身不受到伤害的情况下，令敌人承受坠落物伤害。</p><p>刀光枪火（1-3）<br> 该专长仅在同时持用一把刀类白刃武器与一把远程枪械武器时生效。<br> 1级：远近兼修<br> 在满足专长生效条件时，以刀类武器进行的攻击获得武器破甲数额等量的专长加值，以枪械武器进行的攻击获得武器高速数额等量的专长加值；上述专长加值的上限等同于专长等级。<br> 2级：远突近攻<br> 进行一次枪械射击/白刃攻击后，下一次以所持的另一把武器发起的攻击额外获得该专长提供的专长加值等量的附加成功。<br> 3级：刀枪共舞<br> 在满足专长生效条件时，自身处于敌方触及范围内时，枪械射击不会承受减值；进行一次枪械射击/白刃攻击后，下一次，以所持的另一把武器发起的攻击额外具有【高速5】。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',41)])])}const m=p(n,[["render",d]]);export{f as __pageData,m as default};
